// Validate and extract uploaded file
const formData = $input.item.json;

// Get file data from form submission
const fileData = formData['Floor Plan Image'];

if (!fileData || !fileData.data) {
  throw new Error('No floor plan image uploaded');
}

// Validate file type
const validTypes = ['image/png', 'image/jpeg', 'image/jpg', 'image/webp'];
const mimeType = fileData.mimeType || 'image/png';

if (!validTypes.some(t => mimeType.includes(t.split('/')[1]))) {
  throw new Error(`Invalid file type: ${mimeType}. Accepted: PNG, JPG, WEBP`);
}

// Validate file size (max 10MB)
const maxSize = 10 * 1024 * 1024;
const fileSize = fileData.data.length * 0.75; // Base64 is ~33% larger
if (fileSize > maxSize) {
  throw new Error('File too large. Maximum size is 10MB.');
}

// Extract style preference
const style = formData['Property Style'] || 'Modern';
const styleDescriptors = {
  'Modern': 'modern contemporary design with clean lines, neutral colors, and minimalist furniture',
  'Traditional': 'traditional classic design with warm wood tones, ornate details, and elegant furniture',
  'Minimalist': 'ultra-minimalist design with sparse furniture, white walls, and essential items only',
  'Industrial': 'industrial loft style with exposed brick, metal fixtures, and raw materials',
  'Scandinavian': 'Scandinavian design with light wood, cozy textiles, and hygge atmosphere'
};

return {
  json: {
    floorPlanBase64: fileData.data,
    floorPlanMimeType: mimeType,
    email: formData['Email'],
    style: style,
    styleDescription: styleDescriptors[style],
    timestamp: new Date().toISOString()
  }
};

// Universal polling handler for Kie.ai jobs
const data = $input.item.json;
const config = {
  maxRetries: 120,
  taskId: data.data?.taskId || data.taskId,
  currentRetry: data._retryCount || 0
};

// Check for timeout
if (config.currentRetry >= config.maxRetries) {
  return {
    json: {
      success: false,
      error: 'Generation timeout after 6 minutes',
      taskId: config.taskId
    }
  };
}

// Check status based on API response structure
const state = data.data?.state;
const successFlag = data.data?.successFlag;
const code = data.code;

// Image API uses 'state', Video API uses 'successFlag'
const isComplete = state === 'success' || successFlag === 1;
const isFailed = state === 'fail' || state === 'failed' || successFlag === 2 || successFlag === 3;
const isError = code && code !== 200;

if (isComplete) {
  let resultUrl = '';

  // Try to extract URL from different response structures
  if (data.data?.resultJson) {
    try {
      const parsed = JSON.parse(data.data.resultJson);
      resultUrl = parsed.resultUrls?.[0] || '';
    } catch (e) {}
  }
  if (!resultUrl && data.data?.response?.resultUrls) {
    resultUrl = data.data.response.resultUrls[0];
  }

  return {
    json: {
      success: true,
      ready: true,
      resultUrl: resultUrl,
      taskId: config.taskId
    }
  };
}

if (isFailed || isError) {
  return {
    json: {
      success: false,
      ready: true,
      error: data.data?.errorMessage || data.msg || 'Generation failed',
      taskId: config.taskId
    }
  };
}

// Still processing - continue polling
return {
  json: {
    ...data,
    success: false,
    ready: false,
    _retryCount: config.currentRetry + 1,
    taskId: config.taskId
  }
};

// Reusable polling handler
const data = $input.item.json;
const maxRetries = 120;
const currentRetry = data._retryCount || 0;

if (currentRetry >= maxRetries) {
  return { json: { success: false, ready: true, error: 'Timeout', taskId: data.data?.taskId } };
}

const state = data.data?.state;
const code = data.code;

if (state === 'success') {
  let resultUrl = '';
  if (data.data?.resultJson) {
    try {
      const parsed = JSON.parse(data.data.resultJson);
      resultUrl = parsed.resultUrls?.[0] || '';
    } catch (e) {}
  }
  return { json: { success: true, ready: true, resultUrl, taskId: data.data?.taskId } };
}

if (state === 'fail' || state === 'failed' || (code && code !== 200)) {
  return { json: { success: false, ready: true, error: data.msg || 'Failed', taskId: data.data?.taskId } };
}

return { json: { ...data, success: false, ready: false, _retryCount: currentRetry + 1, taskId: data.data?.taskId } };

